import{_ as e,o as l,c as n,a2 as s}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"八卦与五脏","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/03-八卦与五脏.md","filePath":"tcm-data/09-医易同源/03-八卦与五脏.md","lastUpdated":1781084559000}'),a={name:"tcm-data/09-医易同源/03-八卦与五脏.md"};function d(g,t,r,i,o,x){return l(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="八卦与五脏" tabindex="-1">八卦与五脏 <a class="header-anchor" href="#八卦与五脏" aria-label="Permalink to &quot;八卦与五脏&quot;">​</a></h1><blockquote><p>八卦与人体脏腑经络的对应关系 医易同源的核心：八卦模型 = 人体模型</p></blockquote><hr><h2 id="一、八卦基础" tabindex="-1">一、八卦基础 <a class="header-anchor" href="#一、八卦基础" aria-label="Permalink to &quot;一、八卦基础&quot;">​</a></h2><h3 id="八卦符号与属性" tabindex="-1">八卦符号与属性 <a class="header-anchor" href="#八卦符号与属性" aria-label="Permalink to &quot;八卦符号与属性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦名</th><th style="text-align:left;">符号</th><th style="text-align:left;">自然</th><th style="text-align:left;">属性</th><th style="text-align:left;">方向</th><th style="text-align:left;">家庭成员</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>乾</strong></td><td style="text-align:left;">☰</td><td style="text-align:left;">天</td><td style="text-align:left;">健</td><td style="text-align:left;">西北</td><td style="text-align:left;">父</td></tr><tr><td style="text-align:left;"><strong>坤</strong></td><td style="text-align:left;">☷</td><td style="text-align:left;">地</td><td style="text-align:left;">顺</td><td style="text-align:left;">西南</td><td style="text-align:left;">母</td></tr><tr><td style="text-align:left;"><strong>震</strong></td><td style="text-align:left;">☳</td><td style="text-align:left;">雷</td><td style="text-align:left;">动</td><td style="text-align:left;">东</td><td style="text-align:left;">长男</td></tr><tr><td style="text-align:left;"><strong>巽</strong></td><td style="text-align:left;">☴</td><td style="text-align:left;">风</td><td style="text-align:left;">入</td><td style="text-align:left;">东南</td><td style="text-align:left;">长女</td></tr><tr><td style="text-align:left;"><strong>坎</strong></td><td style="text-align:left;">☵</td><td style="text-align:left;">水</td><td style="text-align:left;">陷</td><td style="text-align:left;">北</td><td style="text-align:left;">中男</td></tr><tr><td style="text-align:left;"><strong>离</strong></td><td style="text-align:left;">☲</td><td style="text-align:left;">火</td><td style="text-align:left;">丽</td><td style="text-align:left;">南</td><td style="text-align:left;">中女</td></tr><tr><td style="text-align:left;"><strong>艮</strong></td><td style="text-align:left;">☶</td><td style="text-align:left;">山</td><td style="text-align:left;">止</td><td style="text-align:left;">东北</td><td style="text-align:left;">少男</td></tr><tr><td style="text-align:left;"><strong>兑</strong></td><td style="text-align:left;">☱</td><td style="text-align:left;">泽</td><td style="text-align:left;">说（悦）</td><td style="text-align:left;">西</td><td style="text-align:left;">少女</td></tr></tbody></table><hr><h2 id="二、八卦与五脏六腑对应" tabindex="-1">二、八卦与五脏六腑对应 <a class="header-anchor" href="#二、八卦与五脏六腑对应" aria-label="Permalink to &quot;二、八卦与五脏六腑对应&quot;">​</a></h2><h3 id="后天八卦人体对应" tabindex="-1">后天八卦人体对应 <a class="header-anchor" href="#后天八卦人体对应" aria-label="Permalink to &quot;后天八卦人体对应&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>               离（心·火）</span></span>
<span class="line"><span>              ☲</span></span>
<span class="line"><span>                  ↑</span></span>
<span class="line"><span>    巽（胆）             坤（脾）</span></span>
<span class="line"><span>     ☴                  ☷</span></span>
<span class="line"><span>         震（肝）   中土   兑（肺）</span></span>
<span class="line"><span>          ☳          ☱</span></span>
<span class="line"><span>    艮（胃）             乾（大肠）</span></span>
<span class="line"><span>     ☶                  ☰</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>               坎（肾·膀胱）</span></span>
<span class="line"><span>                ☵</span></span></code></pre></div><h3 id="逐卦详解" tabindex="-1">逐卦详解 <a class="header-anchor" href="#逐卦详解" aria-label="Permalink to &quot;逐卦详解&quot;">​</a></h3><p><strong>乾卦☰——天·大肠/头</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">大肠、头部、督脉</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">纯阳刚健，主气</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">便秘、头痛、阳气不足</td></tr><tr><td style="text-align:left;"><strong>普光相关</strong></td><td style="text-align:left;">大便尚可，但头前倾（乾气不足）</td></tr></tbody></table><p><strong>坤卦☷——地·脾/肉</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">脾、肌肉、任脉</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">厚德载物，主运化</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">腹胀、湿盛、肌肉松软</td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">⭐ 两人都涉及——普光土湿，普明中虚</td></tr></tbody></table><p><strong>震卦☳——雷·肝</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">肝、筋、足</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主动、主升发</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">肝郁、抽筋、目疾</td></tr><tr><td style="text-align:left;"><strong>普光相关</strong></td><td style="text-align:left;">目干涩、抽筋、肝脾痛——木郁不升</td></tr><tr><td style="text-align:left;"><strong>普明相关</strong></td><td style="text-align:left;">烦躁、月经先期——木郁化火</td></tr></tbody></table><p><strong>巽卦☴——风·胆</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">胆、三焦</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主入、主疏泄</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">口苦、犹豫、胆怯</td></tr></tbody></table><p><strong>坎卦☵——水·肾</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">肾、膀胱、骨</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主藏精、主水</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">腰凉、水肿、恐</td></tr><tr><td style="text-align:left;"><strong>普光相关</strong></td><td style="text-align:left;">⭐ <strong>核心卦</strong>——腰凉、脚冷、水寒</td></tr></tbody></table><p><strong>离卦☲——火·心</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">心、小肠、血脉</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主明、主血脉</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">心烦、失眠、口疮</td></tr><tr><td style="text-align:left;"><strong>普光相关</strong></td><td style="text-align:left;">前胸出汗多（心火不降）</td></tr><tr><td style="text-align:left;"><strong>普明相关</strong></td><td style="text-align:left;">潮热、入睡困难（心火上浮）</td></tr></tbody></table><p><strong>艮卦☶——山·胃</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">胃、皮肤</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主止、主受纳</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">胃胀、不思食</td></tr><tr><td style="text-align:left;"><strong>普明相关</strong></td><td style="text-align:left;">饭后腹胀（胃纳而不化）</td></tr></tbody></table><p><strong>兑卦☱——泽·肺</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>中医对应</strong></td><td style="text-align:left;">肺、鼻、皮肤</td></tr><tr><td style="text-align:left;"><strong>生理特性</strong></td><td style="text-align:left;">主收、主降</td></tr><tr><td style="text-align:left;"><strong>病理表现</strong></td><td style="text-align:left;">咳嗽、鼻塞、皮肤干燥</td></tr><tr><td style="text-align:left;"><strong>普光相关</strong></td><td style="text-align:left;">鼻疮、皮肤干燥蜕皮</td></tr></tbody></table><hr><h2 id="三、黄元御-一气周流-的八卦解释" tabindex="-1">三、黄元御&quot;一气周流&quot;的八卦解释 <a class="header-anchor" href="#三、黄元御-一气周流-的八卦解释" aria-label="Permalink to &quot;三、黄元御&quot;一气周流&quot;的八卦解释&quot;">​</a></h2><p>黄元御的左升右降模型，在八卦中可以清晰地表达：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>             离（心）</span></span>
<span class="line"><span>               ↓ 降（金鼎汤法）</span></span>
<span class="line"><span>   震（肝）← 中土（坤艮）→ 兑（肺）</span></span>
<span class="line"><span>               ↑ 升（天魂汤法）</span></span>
<span class="line"><span>             坎（肾）</span></span></code></pre></div><p><strong>普光处方&quot;温潜黄芽天魂汤&quot;的八卦逻辑：</strong></p><ul><li><strong>坎水寒</strong> → 附子温水（补坎阳）</li><li><strong>震木郁</strong> → 桂枝达木（升震）</li><li><strong>离火浮</strong> → 龙牡潜降（降离）</li><li><strong>中土湿</strong> → 黄芽汤运转中轴（厚坤土）</li></ul><p><strong>这就是一张&quot;医易处方&quot;。</strong></p><hr><h2 id="四、卦象诊断法" tabindex="-1">四、卦象诊断法 <a class="header-anchor" href="#四、卦象诊断法" aria-label="Permalink to &quot;四、卦象诊断法&quot;">​</a></h2><p>根据面象、神态、症状判断&quot;主卦&quot;：</p><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">面象</th><th style="text-align:left;">神态</th><th style="text-align:left;">主病</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>坎象</strong></td><td style="text-align:left;">面色黑/暗沉</td><td style="text-align:left;">沉静、欲寐</td><td style="text-align:left;">肾寒</td></tr><tr><td style="text-align:left;"><strong>离象</strong></td><td style="text-align:left;">面色红/赤</td><td style="text-align:left;">烦躁、易怒</td><td style="text-align:left;">心火上炎</td></tr><tr><td style="text-align:left;"><strong>震象</strong></td><td style="text-align:left;">面色青</td><td style="text-align:left;">易怒、紧张</td><td style="text-align:left;">肝郁</td></tr><tr><td style="text-align:left;"><strong>兑象</strong></td><td style="text-align:left;">面色白</td><td style="text-align:left;">悲忧</td><td style="text-align:left;">肺气虚</td></tr><tr><td style="text-align:left;"><strong>坤象</strong></td><td style="text-align:left;">面色黄/暗沉如尘土</td><td style="text-align:left;">懒言、倦怠</td><td style="text-align:left;">脾湿</td></tr><tr><td style="text-align:left;"><strong>艮象</strong></td><td style="text-align:left;">面色黄</td><td style="text-align:left;">思虑、固执</td><td style="text-align:left;">胃滞</td></tr></tbody></table><h3 id="普光面诊的卦象分析" tabindex="-1">普光面诊的卦象分析 <a class="header-anchor" href="#普光面诊的卦象分析" aria-label="Permalink to &quot;普光面诊的卦象分析&quot;">​</a></h3><ul><li><strong>面色暗沉如覆尘土</strong> → <strong>坤象过重</strong>（土湿）</li><li><strong>腰凉脚冷</strong> → <strong>坎象不足</strong>（水寒）</li><li><strong>目干涩易怒</strong> → <strong>震象不升</strong>（木郁）</li><li><strong>口渴前胸出汗</strong> → <strong>离象浮动</strong>（火不降）</li></ul><p><strong>主卦</strong>：坤☷（土湿）+ 坎☵（水寒）</p><h3 id="普明面诊的卦象分析-推测" tabindex="-1">普明面诊的卦象分析（推测） <a class="header-anchor" href="#普明面诊的卦象分析-推测" aria-label="Permalink to &quot;普明面诊的卦象分析（推测）&quot;">​</a></h3><ul><li><strong>面部生斑</strong> → 坤象不足+离象不和</li><li><strong>烦躁易怒</strong> → 震象+离象（木火相生而太过）</li><li><strong>手脚冰凉</strong> → 坎象不足</li><li><strong>经期腰凉</strong> → 坎象+坤象不足</li></ul><hr><h2 id="五、八卦用药法" tabindex="-1">五、八卦用药法 <a class="header-anchor" href="#五、八卦用药法" aria-label="Permalink to &quot;五、八卦用药法&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">卦</th><th style="text-align:left;">补法</th><th style="text-align:left;">药物</th><th style="text-align:left;">泻法</th><th style="text-align:left;">药物</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>坎（水）</strong></td><td style="text-align:left;">温坎阳</td><td style="text-align:left;">附子、肉桂</td><td style="text-align:left;">清坎热</td><td style="text-align:left;">黄柏、知母</td></tr><tr><td style="text-align:left;"><strong>离（火）</strong></td><td style="text-align:left;">养离阴</td><td style="text-align:left;">酸枣仁、麦冬</td><td style="text-align:left;">降离火</td><td style="text-align:left;">黄连、栀子</td></tr><tr><td style="text-align:left;"><strong>震（木）</strong></td><td style="text-align:left;">升震阳</td><td style="text-align:left;">桂枝、川芎</td><td style="text-align:left;">平震逆</td><td style="text-align:left;">白芍、柴胡</td></tr><tr><td style="text-align:left;"><strong>兑（金）</strong></td><td style="text-align:left;">补兑气</td><td style="text-align:left;">黄芪、人参</td><td style="text-align:left;">清兑热</td><td style="text-align:left;">黄芩、桑白皮</td></tr><tr><td style="text-align:left;"><strong>坤（土）</strong></td><td style="text-align:left;">厚坤土</td><td style="text-align:left;">人参、白术</td><td style="text-align:left;">泻坤湿</td><td style="text-align:left;">茯苓、泽泻</td></tr><tr><td style="text-align:left;"><strong>艮（土）</strong></td><td style="text-align:left;">温艮阳</td><td style="text-align:left;">干姜、砂仁</td><td style="text-align:left;">清艮积</td><td style="text-align:left;">大黄、枳实</td></tr><tr><td style="text-align:left;"><strong>乾（天）</strong></td><td style="text-align:left;">补乾阳</td><td style="text-align:left;">鹿茸、巴戟天</td><td style="text-align:left;">清乾热</td><td style="text-align:left;">石膏</td></tr><tr><td style="text-align:left;"><strong>巽（风）</strong></td><td style="text-align:left;">和巽气</td><td style="text-align:left;">柴胡、薄荷</td><td style="text-align:left;">清巽热</td><td style="text-align:left;">黄芩、龙胆草</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展至六十四卦与人体经络全对应（孟喜卦气说）等内容。</em></p>`,48)])])}const h=e(a,[["render",d]]);export{f as __pageData,h as default};
